const { execSync } = require('child_process');
const fs = require('fs');

const items = $input.all().map(item => item.json);

const n8nIn  = '/data/ffmpeg/input';
const n8nOut = '/data/ffmpeg/output';
const contIn = '/ffmpeg/input';
const contOut= '/ffmpeg/output';

if (!fs.existsSync(n8nIn))  fs.mkdirSync(n8nIn,  { recursive: true });
if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

function run(cmd, timeoutMs) {
  const t = timeoutMs || 120000;
  console.log('CMD: ' + cmd.slice(0, 200));
  let out = '';
  try { out = execSync(cmd, { encoding: 'utf-8', timeout: t }); }
  catch(e) { out = (e.stdout || '') + (e.stderr || ''); }
  return out.toString();
}

function toDiskPath(contPath) {
  return contPath
    .replace('/ffmpeg/input', '/data/ffmpeg/input')
    .replace('/ffmpeg/clips', '/data/ffmpeg/clips');
}

function assembleOne(data) {
  const jobId = data.job_id;
  const videoPaths = data.video_paths;
  const N = videoPaths.length;
  const clipDurations = data.clip_durations || Array(N).fill(5.0);
  const TRANS = 0.3;

  if (N < 2) throw new Error('Job ' + jobId + ': need at least 2 clips, got ' + N);

  for (let i = 0; i < N; i++) {
    const diskPath = toDiskPath(videoPaths[i]);
    if (!fs.existsSync(diskPath)) throw new Error('Job ' + jobId + ': clip ' + i + ' missing: ' + videoPaths[i]);
  }

  // Normalize each clip to 1080x1920 @ 24fps
  for (let i = 0; i < N; i++) {
    run('docker exec phys_ffmpeg_runner ffmpeg -y -i "' + videoPaths[i] + '" -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" -r 24 -c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p -an "' + contIn + '/' + jobId + '_clip' + i + '_norm.mp4"', 120000);
  }

  // Xfade assembly with dynamic offsets from actual clip durations
  let withTransitions;
  if (N === 1) {
    withTransitions = contIn + '/' + jobId + '_clip0_norm.mp4';
  } else {
    const inputs = Array.from({length:N}, (_,i) => '-i "' + contIn + '/' + jobId + '_clip' + i + '_norm.mp4"').join(' ');
    let xf = '';
    let prev = '[0:v]';
    let offset = 0;
    for (let i = 1; i < N; i++) {
      const o = (i === N-1) ? '[vout]' : '[x'+i+']';
      offset += clipDurations[i-1] - TRANS;
      xf += prev + '['+i+':v]xfade=transition=fade:duration=' + TRANS + ':offset=' + offset.toFixed(3) + o + ';';
      prev = o;
    }
    run('docker exec phys_ffmpeg_runner ffmpeg -y ' + inputs + ' -filter_complex "' + xf.slice(0,-1) + '" -map "[vout]" -c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p "' + contIn + '/' + jobId + '_xfade.mp4"', 300000);
    withTransitions = contIn + '/' + jobId + '_xfade.mp4';
  }

  const hlWords = (data.highlight_keywords || []).map(w => w.toLowerCase());
  function esc(s) { return s.replace(/[.+?^${}()|[\]\\*]/g, '\\$&'); }
  function addHighlights(text) {
    let r = text;
    hlWords.forEach(word => {
      const re = new RegExp('(' + esc(word) + ')', 'gi');
      var _bs = String.fromCharCode(92); r = r.replace(re, '{' + _bs + 'c&HFF9600&}$1{' + _bs + 'c&HFFFFFF&}');
    });
    return r;
  }
  const narTxt = (data.narration || '').replace(/_/g, ' ').replace(/\s*-\s*/g, ' ').replace(/"/g, "'").replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
  const hlText = addHighlights(narTxt);
  const totalDur = data.audio_duration || clipDurations.reduce((a,d,i) => a + (i===0 ? d : d - TRANS), 0);
  function secToAss(s) {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sec = Math.floor(s % 60);
    const cs = Math.round((s % 1) * 100);
    return h + ':' + String(m).padStart(2,'0') + ':' + String(sec).padStart(2,'0') + '.' + String(cs).padStart(2,'0');
  }

  const videoDur = Math.ceil(totalDur) + 2;
  const assContent =
    '[Script Info]\nScriptType: v4.00+\nPlayResX: 1080\nPlayResY: 1920\n\n' +
    '[V4+ Styles]\n' +
    'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding\n' +
    'Style: Caption,Liberation Sans,52,&H00FFFFFF,&H000000FF,&H00000000,&H80000000,-1,0,1,3,0,7,60,60,470,1\n\n' +
    '[Events]\nFormat: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n' +
    'Dialogue: 0,0:00:00.00,' + secToAss(videoDur) + ',Caption,,0,0,0,,' + hlText + '\n';

  fs.writeFileSync(n8nIn + '/' + jobId + '.ass', assContent, 'utf8');
  console.log('Job ' + jobId + ': ASS written. Highlights: ' + hlWords.join(', '));

  const logoPath = '/ffmpeg/config/icon/logo.png';
  const tickPath = '/ffmpeg/config/icon/Blue verification badge emblem.png';
  const bgmDir   = '/ffmpeg/config/bgm';

  const hasLogo = run('docker exec phys_ffmpeg_runner test -f "' + logoPath + '" && echo OK').includes('OK');
  const hasTick = run('docker exec phys_ffmpeg_runner test -f "' + tickPath + '" && echo OK').includes('OK');

  let narFile = null;
  if (data.audio_path) {
    narFile = data.audio_path.replace('/data/ffmpeg', '/ffmpeg');
    if (!run('docker exec phys_ffmpeg_runner test -f "' + narFile + '" && echo OK').includes('OK')) {
      console.log('Job ' + jobId + ': narration not found: ' + narFile);
      narFile = null;
    }
  }

  let bgmFile = data.bgm_path ? data.bgm_path.replace('/data/ffmpeg', '/ffmpeg') : null;
  if (!bgmFile) {
    const ls = run('docker exec phys_ffmpeg_runner ls "' + bgmDir + '" 2>/dev/null').split('\n');
    const mp3 = ls.find(f => f.trim().endsWith('.mp3'));
    if (mp3) bgmFile = bgmDir + '/' + mp3.trim();
  }
  const hasBgm = !!(bgmFile && run('docker exec phys_ffmpeg_runner test -f "' + bgmFile + '" && echo OK').includes('OK'));
  console.log('Job ' + jobId + ': narFile=' + narFile + ' hasBgm=' + hasBgm);

  const inp   = ['-i "' + withTransitions + '"'];
  const logoI = hasLogo ? inp.push('-i "' + logoPath + '"') - 1 : -1;
  const tickI = hasTick ? inp.push('-i "' + tickPath + '"') - 1 : -1;
  const narI  = narFile  ? inp.push('-i "' + narFile  + '"') - 1 : -1;
  const bgmI  = hasBgm   ? inp.push('-i "' + bgmFile  + '"') - 1 : -1;

  let lbl = 0;
  let vf  = '';
  let cur = '0:v';

  if (hasLogo) {
    vf += '[' + logoI + ':v]scale=110:110,format=rgba[lg];[' + cur + '][lg]overlay=x=40:y=293:format=auto[vb' + lbl + ']';
    cur = 'vb' + lbl; lbl++;
  }

  vf += (vf ? ';' : '') + '[' + cur + "]drawtext=text='SchrodingersCat':fontcolor=white:fontsize=52:x=178:y=308:bordercolor=black:borderw=3[vb" + lbl + ']';
  cur = 'vb' + lbl; lbl++;

  if (hasTick) {
    vf += ';[' + tickI + ":v]crop='min(iw,ih)':'min(iw,ih)',scale=72:72,format=rgba[tk];[" + cur + '][tk]overlay=x=600:y=300:format=auto[vb' + lbl + ']';
    cur = 'vb' + lbl; lbl++;
  }

  vf += ';[' + cur + "]drawtext=text='@SchrodingersCat':fontcolor=white:fontsize=34:x=178:y=377:bordercolor=black:borderw=2[vb" + lbl + ']';
  cur = 'vb' + lbl; lbl++;

  vf += ";[" + cur + "]subtitles=filename='" + contIn + '/' + jobId + ".ass'[outv]";

  let afilters = '';
  let amap     = '-an';

  if (narFile && hasBgm) {
    afilters = ';[' + narI + ':a]volume=1.0[nar];[' + bgmI + ':a]volume=0.25[bgm];[nar][bgm]amix=inputs=2:duration=first:dropout_transition=2[aout]';
    amap     = '-map "[aout]"';
  } else if (narFile) {
    afilters = ';[' + narI + ':a]aformat=sample_fmts=fltp[aout]';
    amap     = '-map "[aout]"';
  } else if (hasBgm) {
    afilters = ';[' + bgmI + ':a]volume=0.85[aout]';
    amap     = '-map "[aout]"';
  }

  const fullFilter = vf + afilters;
  const dur = data.audio_duration ? Math.ceil(data.audio_duration) + 2 : 30;
  const hasAudio = amap !== '-an';

  const cmd =
    'docker exec phys_ffmpeg_runner ffmpeg -y ' + inp.join(' ') +
    ' -filter_complex "' + fullFilter + '" -map "[outv]" ' + amap +
    ' -c:v libx264 -crf 18 -preset fast -pix_fmt yuv420p -movflags +faststart' +
    (hasAudio ? ' -c:a aac -b:a 192k' : '') +
    ' -t ' + dur + ' "' + contOut + '/' + jobId + '_final.mp4" && echo FINAL_OK';

  const result = run(cmd, 900000);
  if (!result.includes('FINAL_OK')) throw new Error('Job ' + jobId + ': final render failed: ' + result.slice(-800));

  const finalPath = n8nOut + '/' + jobId + '_final.mp4';
  if (!fs.existsSync(finalPath)) throw new Error('Job ' + jobId + ': output missing: ' + finalPath);

  return Object.assign({}, data, { final_video_path: finalPath, output_filename: jobId + '_final.mp4' });
}

console.log('Assembling ' + items.length + ' video(s)...');
const results = items.map(assembleOne);
return results.map(r => ({ json: r }));

const fs = require('fs');
const items = $input.all().map(item => item.json);

return items.map(item => {
  const filePath = item.final_video_path;
  if (!fs.existsSync(filePath)) throw new Error('Final video not found: ' + filePath);
  const b64 = fs.readFileSync(filePath).toString('base64');
  return {
    json: item,
    binary: {
      data: {
        data:          b64,
        mimeType:      'video/mp4',
        fileName:      item.output_filename,
        fileExtension: 'mp4'
      }
    }
  };
});

const permResults    = $input.all();
const assembleResults = $('Assemble Video').all();
const uploadResults  = $('Upload Animation to Drive').all();

return permResults.map((_, i) => {
  const assemble = assembleResults[i].json;
  const upload   = uploadResults[i].json;
  const fileId   = upload.id;
  const videoUrl = 'https://drive.usercontent.google.com/download?id=' + fileId + '&export=download';
  const renderTimeSec = Math.round((Date.now() - assemble.start_time) / 1000);
  console.log('Stage 2 complete. Job: ' + assemble.job_id + ', Drive: ' + fileId + ', Time: ' + renderTimeSec + 's');
  return { json: {
    job_id:             assemble.job_id,
    topic:              assemble.topic,
    title:              assemble.title,
    narration:          assemble.narration,
    hashtags:           assemble.hashtags,
    highlight_keywords: assemble.highlight_keywords || [],
    final_video_path:   assemble.final_video_path,
    output_filename:    assemble.output_filename,
    video_url:          videoUrl,
    drive_file_id:      fileId,
    render_time_seconds:renderTimeSec,
    sheet_row:          assemble.sheet_row,
    queue_row_index:    assemble.queue_row_index,
    readyForVideoAt:    assemble.readyForVideoAt,
    status: 'stage2_complete'
  }};
});

const stage2Results = $('Stage 2 Done').all();
return stage2Results.map(item => {
  const d = item.json;
  return { json: {
    job_id:           d.job_id,
    title:            d.title,
    topic:            d.topic,
    narration:        d.narration || '',
    description:      ((d.narration || d.topic) || '').slice(0, 500),
    hashtags:         d.hashtags || '',
    highlight_keywords: d.highlight_keywords || [],
    final_video_path: d.final_video_path,
    output_filename:  d.output_filename,
    drive_file_id:    d.drive_file_id,
    drive_video_url:  d.video_url,
    sheet_row:        d.sheet_row,
    queue_row_index:  d.queue_row_index,
    readyForVideoAt:  d.readyForVideoAt,
    callback_url:     null
  }};
});

const driveFiles = $('List Drive Clips').item.json.files || [];
if (!driveFiles.length) throw new Error('No files found in Drive folder');

const data = $('Extract Payload').item.json;

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

const shuffled = shuffle(driveFiles).slice(0, 10);
console.log('Picked ' + shuffled.length + ' random files from Drive for job ' + data.job_id);

return shuffled.map(f => ({ json: { fileId: f.id, fileName: f.name, jobData: data } }));

const fs = require('fs');
const { execSync } = require('child_process');

const fileName = $input.item.json.fileName;
const jobData = $input.item.json.jobData;

const clipName = fileName.endsWith('_norm.mp4') ? fileName : fileName.replace(/\.[^.]+$/, '') + '_norm.mp4';
const localPath = '/data/ffmpeg/clips/' + clipName;
const contPath  = '/ffmpeg/clips/' + clipName;

const buf = await this.helpers.getBinaryDataBuffer($input.item, 'data');
fs.writeFileSync(localPath, buf);

let duration = 5.0;
try {
  const out = execSync(
    'docker exec phys_ffmpeg_runner ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "' + contPath + '"',
    { encoding: 'utf8', timeout: 15000 }
  ).trim();
  const d = parseFloat(out);
  if (d > 0.5) duration = d;
} catch(e) { console.log('ffprobe failed for ' + clipName + ': ' + e.message); }

console.log('Saved: ' + clipName + ' (' + duration.toFixed(2) + 's)');
return { json: { contPath, duration, clipName, jobData } };

const items = $input.first().json.data || [];
if (!items.length) throw new Error('No clips downloaded from Drive');

const jobData = items[0].jobData;
const TRANS = 0.3;
const targetDur = jobData.audio_duration || 19.1;

let assembled = 0;
const selected = [];
const durations = [];

for (const item of items) {
  if (assembled >= targetDur) break;
  selected.push(item.contPath);
  durations.push(item.duration);
  assembled += selected.length > 1 ? (item.duration - TRANS) : item.duration;
}

if (!selected.length) throw new Error('No clips could be selected for job ' + jobData.job_id);

console.log('Job ' + jobData.job_id + ': ' + selected.length + ' clips, ~' + assembled.toFixed(2) + 's (target ' + targetDur + 's)');

return [{ json: {
  ...jobData,
  video_paths: selected,
  clip_durations: durations,
  clips_count: selected.length,
  clip_source: 'google_drive'
}}];
